import { NextResponse } from 'next/server';
import { spawnSync } from 'child_process';
import { users } from '@/lib/db';

function normalizeMac(raw: string): string {
  const hex = raw.replace(/[:\-.]/g, '').toLowerCase();
  if (hex.length !== 12) return '';
  return hex.match(/.{2}/g)!.join(':');
}

function parseArpOutput(output: string): string[] {
  const macRegex = /([0-9a-fA-F]{1,2}[:\-][0-9a-fA-F]{1,2}[:\-][0-9a-fA-F]{1,2}[:\-][0-9a-fA-F]{1,2}[:\-][0-9a-fA-F]{1,2}[:\-][0-9a-fA-F]{1,2})/g;
  const found = new Set<string>();
  let match: RegExpExecArray | null;
  while ((match = macRegex.exec(output)) !== null) {
    const n = normalizeMac(match[1]);
    if (n && n !== 'ff:ff:ff:ff:ff:ff' && n !== '00:00:00:00:00:00') {
      found.add(n);
    }
  }
  return Array.from(found);
}

// Ping broadcast to refresh the ARP cache so recently-connected devices appear
function populateArpCache(): void {
  try {
    const isMac = process.platform === 'darwin';
    if (isMac) {
      // Get default interface and its IP, then broadcast-ping to refresh ARP cache
      const ifaceResult = spawnSync('netstat', ['-rn'], { timeout: 30000 });
      const ifaceLine = ifaceResult.stdout?.toString().split('\n').find(l => l.startsWith('default'));
      const iface = ifaceLine?.trim().split(/\s+/)[5] || 'en0';
      const ipResult = spawnSync('ipconfig', ['getifaddr', iface], { timeout: 30000 });
      const ip = ipResult.stdout?.toString().trim() || '';
      const parts = ip.split('.');
      if (parts.length === 4) {
        const bcast = `${parts[0]}.${parts[1]}.${parts[2]}.255`;
        spawnSync('ping', ['-c', '2', '-t', '1', bcast], { timeout: 30000 });
      }
    } else {
      const routeResult = spawnSync('ip', ['route', 'show', 'default'], { timeout: 30000 });
      const iface = routeResult.stdout?.toString().match(/dev\s+(\S+)/)?.[1] || 'eth0';
      const addrResult = spawnSync('ip', ['addr', 'show', iface], { timeout: 30000 });
      const ip = addrResult.stdout?.toString().match(/inet\s+([\d.]+)\//)?.[1] || '';
      if (ip) {
        const parts = ip.split('.');
        const bcast = `${parts[0]}.${parts[1]}.${parts[2]}.255`;
        spawnSync('ping', ['-c', '2', '-W', '1', '-b', bcast], { timeout: 30000 });
      }
    }
  } catch {
    // Non-fatal — arp -a will still return cached results
  }
}

export async function GET() {
  try {
    populateArpCache();

    let arpOutput = '';
    try {
      // Use spawnSync (no shell) with generous timeout — macOS process spawn can be slow
      const result = spawnSync('/usr/sbin/arp', ['-a'], { timeout: 30000 });
      if (result.error) throw result.error;
      arpOutput = result.stdout?.toString() || '';
    } catch {
      return NextResponse.json(
        { error: 'arp command unavailable on this server', onlineMacs: [], matchedStudents: [], unmatchedStudents: [] },
        { status: 500 }
      );
    }

    const onlineMacs = parseArpOutput(arpOutput);
    const allUsers = users.getAll();

    const matchedStudents = allUsers
      .filter(u => u.role === 'student' && u.macAddress && onlineMacs.includes(normalizeMac(u.macAddress)))
      .map(u => ({ id: u.id, name: u.name, email: u.email }));

    const unmatchedStudents = allUsers
      .filter(u => u.role === 'student' && !u.macAddress)
      .map(u => ({ id: u.id, name: u.name, email: u.email }));

    return NextResponse.json({
      onlineMacs,
      matchedStudents,
      unmatchedStudents,
      scannedAt: new Date().toISOString(),
    });
  } catch (error) {
    console.error('Network scan error:', error);
    return NextResponse.json(
      { error: 'Network scan failed', onlineMacs: [], matchedStudents: [], unmatchedStudents: [] },
      { status: 500 }
    );
  }
}
